import akka.actor._
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.scaladsl.Source

object WebhookProxy extends App {
  implicit val system: ActorSystem = ActorSystem("WebhookProxy")
  implicit val executionContext: ExecutionContext = system.dispatcher

  val httpConf = Http().defaultAHSConfig.withRootLogLevel(akka.logging.Logging.InfoLevel)
  val route =
    path("forward") {
      post {
        entity(as[String]) { userUrl =>
          complete {
            Http().singleRequest(HttpRequest(uri = userUrl)) mapResponse { response =>
              Complete(response.entity.dataBytes)
            } recoverWith {
              case e: Exception =>
                val errorMessage = s"Error occurred while forwarding request to ${userUrl}: $e"
                Complete(HttpResponse(status = StatusCodes.InternalServerError, entity = HttpEntity(ContentTypes.`text/plain`, errorMessage)))
            }
          }
        }
      }
    }

  val bindingFuture = Http().bindAndHandle(route, interface = "localhost", port = 8080)

  println(s"Server online at http://localhost:8080/")
}